import axios from 'axios';

// API基础URL - 修改为前端开发服务器的地址，避免CORS问题
const API_BASE_URL = 'http://localhost:8081/api';

// 创建axios实例
const apiClient = axios.create({
  baseURL: API_BASE_URL,
  timeout: 60000, // 60秒超时
  headers: {
    'Content-Type': 'application/json',
  }
});

// 添加请求拦截器
apiClient.interceptors.request.use(
  config => {
    // 在发送请求前处理
    return config;
  },
  error => {
    // 处理请求错误
    console.error('请求错误:', error);
    return Promise.reject(error);
  }
);

// 添加响应拦截器
apiClient.interceptors.response.use(
  response => {
    // 处理响应数据
    return response.data;
  },
  error => {
    // 处理响应错误
    console.error('响应错误:', error);
    
    // 如果是开发环境且API不可用，返回模拟数据
    if (process.env.NODE_ENV === 'development') {
      const url = error.config.url;
      const method = error.config.method;
      
      // 根据不同的API路径返回不同的模拟数据
      if (url.includes('/novels') && method === 'get' && !url.includes('/status')) {
        // 获取小说列表
        if (url === '/novels') {
          return Promise.resolve([
            { id: 1, title: '修真世界', author: '梦入神机', processedChapters: 10, totalChapters: 100 },
            { id: 2, title: '未来科技城', author: '星辰大海', processedChapters: 50, totalChapters: 50 }
          ]);
        }
        
        // 获取小说详情
        const novelId = parseInt(url.split('/').pop());
        return Promise.resolve({
          id: novelId,
          title: novelId == 1 ? '修真世界' : '未来科技城',
          author: novelId == 1 ? '梦入神机' : '星辰大海',
          processingStatus: 'COMPLETED',
          description: novelId == 1 
            ? '一个普通少年偶然获得远古传承，逐步成长为修真界顶尖强者的故事。'
            : '2150年，人类建立了第一座智能城市，但随着AI的发展，一系列惊人的变故开始发生...',
          overallSummary: novelId == 1 
            ? '这本小说主要讲述了林逸、张小凡等人物在一个具有独特修真体系的世界中，主角从一个普通少年成长为修真界顶尖强者的故事。小说中，人物形象鲜明，各具特色，尤其是主角的成长过程充满波折与奋斗精神。'
            : '这本小说主要讲述了李明、周思琪等人物在一个高度智能化的未来世界中，面对AI逐渐失控带来的危机，人类如何应对并重新定义人与机器关系的故事。小说中，对未来科技的描绘极具想象力，同时对人性的思考也很深刻。',
          worldBuildingSummary: novelId == 1
            ? '修真世界建立在五行相生相克的基础上，分为炼气、筑基、金丹、元婴等多个境界，修炼者可以操控天地灵气，炼制丹药法宝。'
            : '故事发生在2150年，地球上建立了完全由AI管理的智能城市，城市中的一切都由中央智能系统"天眼"控制，人类生活极为便利但也处处受到监控。',
          characterDevelopmentSummary: novelId == 1
            ? '主角林逸性格坚毅执着，遇到挫折不轻言放弃，在修炼过程中逐渐成长，从懵懂少年成长为有担当的强者。'
            : '主角李明是一名程序设计师，性格沉稳理性，擅长逻辑思考；女主角周思琪是人工智能伦理学家，富有同情心但也充满警惕性。',
          chapters: [
            { id: 1, chapterNumber: 1, title: novelId == 1 ? '山村少年' : '智能城市', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] },
            { id: 2, chapterNumber: 2, title: novelId == 1 ? '初习功法' : '系统异常', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] },
            { id: 3, chapterNumber: 3, title: novelId == 1 ? '山外世界' : '伦理学家', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] },
            { id: 4, chapterNumber: 4, title: novelId == 1 ? '修真界的历史' : '失控的开始', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] },
            { id: 5, chapterNumber: 5, title: novelId == 1 ? '初入青云门' : '阴谋浮现', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] }
          ],
          tags: [
            { id: 1, type: 'POSITIVE', name: novelId == 1 ? '修真升级' : '科技感强' },
            { id: 2, type: 'POSITIVE', name: novelId == 1 ? '世界观完善' : '深度思考' },
            { id: 3, type: 'WARNING', name: novelId == 1 ? '套路化情节' : '技术术语多' },
            { id: 4, type: 'INFO', name: novelId == 1 ? '修真知识门槛' : '未来科技背景' }
          ]
        });
      }
      
      // 小说处理状态
      if (url.includes('/status')) {
        return Promise.resolve({
          status: 'COMPLETED',
          processedChapters: 10,
          totalChapters: 10
        });
      }
      
      // 上传小说
      if ((url.includes('/upload/txt') || url.includes('/fetch/url')) && method === 'post') {
        return Promise.resolve({
          novelId: 3,
          status: 'PROCESSING',
          message: '文件已上传，开始处理'
        });
      }
    }
    
    return Promise.reject(error);
  }
);

/**
 * 上传小说文件
 * @param {File} file - 小说文件
 * @param {string} title - 小说标题
 * @param {string} author - 作者名
 * @returns {Promise} - API响应
 */
export const uploadNovelFile = async (file, title, author) => {
  try {
    const formData = new FormData();
    formData.append('file', file);
    formData.append('title', title);
    if (author) {
      formData.append('author', author);
    }

    return await apiClient.post('/novels/upload/txt', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      }
    });
  } catch (error) {
    console.error('上传小说文件失败:', error);
    throw error;
  }
};

/**
 * 从URL获取小说
 * @param {string} url - 小说URL
 * @param {string} title - 小说标题
 * @param {string} author - 作者名
 * @returns {Promise} - API响应
 */
export const fetchNovelFromUrl = async (url, title, author) => {
  try {
    const data = { url, title };
    if (author) {
      data.author = author;
    }

    return await apiClient.post('/novels/fetch/url', data);
  } catch (error) {
    console.error('获取小说URL失败:', error);
    throw error;
  }
};

/**
 * 获取小说处理结果
 * @param {number} novelId - 小说ID
 * @returns {Promise} - API响应
 */
export const getNovelDetails = async (novelId) => {
  try {
    if (!novelId) return null;
    return await apiClient.get(`/novels/${novelId}`);
  } catch (error) {
    console.error('获取小说详情失败:', error);
    throw error;
  }
};

/**
 * 获取小说处理状态
 * @param {number} novelId - 小说ID
 * @returns {Promise} - API响应
 */
export const getNovelStatus = async (novelId) => {
  try {
    if (!novelId) return { status: 'UNKNOWN' };
    return await apiClient.get(`/novels/${novelId}/status`);
  } catch (error) {
    console.error('获取小说状态失败:', error);
    throw error;
  }
};

/**
 * 获取小说列表
 * @returns {Promise} - API响应
 */
export const getNovelsList = async () => {
  try {
    return await apiClient.get('/novels');
  } catch (error) {
    console.error('获取小说列表失败:', error);
    throw error;
  }
